using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class ModelTrainerService
{
    private readonly ILogger<ModelTrainerService> _logger;
    private readonly string _dataPath;
    private readonly string _modelPath;

    public ModelTrainerService(ILogger<ModelTrainerService> logger, IWebHostEnvironment env)
    {
        _logger = logger;
        _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
        _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
    }

    public void TrainAndSave()
    {
        var mlContext = new MLContext(seed: 42);

        // Load data
        var data = mlContext.Data.LoadFromTextFile<TicketInput>(
            _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        // Train/test split
        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        // Build pipeline: featurize text + numeric, then classify
        var pipeline = mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "SubjectFeatures", nameof(TicketInput.Subject)))
            .Append(mlContext.Transforms.Text.FeaturizeText(
                "DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
                labelColumnName: "Label", featureColumnName: "Features"))
            .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // Train
        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        // Evaluate
        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(
            predictions, labelColumnName: "Label");

        _logger.LogInformation("========== Model Evaluation ==========");
        _logger.LogInformation("MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
        _logger.LogInformation("MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
        _logger.LogInformation("LogLoss:          {LogLoss:F4}", metrics.LogLoss);
        _logger.LogInformation("LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);

        foreach (var classMetric in metrics.PerClassLogLoss.Select((v, i) => (Value: v, Index: i)))
        {
            _logger.LogInformation("  Class {Index} LogLoss: {LogLoss:F4}",
                classMetric.Index, classMetric.Value);
        }
        _logger.LogInformation("=======================================");

        // Also do cross-validation for more reliable metrics on small datasets
        _logger.LogInformation("Running 5-fold cross-validation...");
        var cvResults = mlContext.MulticlassClassification.CrossValidate(
            data, pipeline, numberOfFolds: 5, labelColumnName: "Label");

        var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
        var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
        _logger.LogInformation("Cross-Validation Avg MacroAccuracy: {Avg:F4}", avgMacro);
        _logger.LogInformation("Cross-Validation Avg MicroAccuracy: {Avg:F4}", avgMicro);

        // Save model
        mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
        _logger.LogInformation("Model saved to {Path}", _modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController : ControllerBase
{
    private readonly PredictionEnginePool<TicketInput, TicketPrediction> _predictionPool;
    private static readonly string[] Categories = ["Billing", "General", "Technical"];

    public TicketsController(PredictionEnginePool<TicketInput, TicketPrediction> predictionPool)
    {
        _predictionPool = predictionPool;
    }

    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority < 1 || request.Priority > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketInput
        {
            Subject = request.Subject ?? string.Empty,
            Description = request.Description ?? string.Empty,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (var i = 0; i < prediction.Score.Length && i < Categories.Length; i++)
        {
            confidence[Categories[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

