public TicketModelMetadata TrainAndSave()
{
    var mlContext = new MLContext(seed: 42);

    // Load data
    var data = mlContext.Data.LoadFromTextFile<TicketInput>(
        _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

    // Train/test split
    var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

    // Build pipeline: featurize text + numeric, then classify
    var pipeline = mlContext.Transforms.Conversion
            .MapValueToKey("Label", nameof(TicketInput.Category))
        .Append(mlContext.Transforms.Text.FeaturizeText(
            "SubjectFeatures", nameof(TicketInput.Subject)))
        .Append(mlContext.Transforms.Text.FeaturizeText(
            "DescriptionFeatures", nameof(TicketInput.Description)))
        .Append(mlContext.Transforms.Concatenate("Features",
            "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
        .Append(mlContext.Transforms.NormalizeMinMax("Features"))
        .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
            labelColumnName: "Label", featureColumnName: "Features"))
        .Append(mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

    // Train
    _logger.LogInformation("Training model...");
    var model = pipeline.Fit(split.TrainSet);

    // Extract ordered label names from the trained model's Score column
    var scoreCol = model.GetOutputSchema(split.TrainSet.Schema)["Score"];
    var slotNames = new Microsoft.ML.Data.VBuffer<ReadOnlyMemory<char>>();
    scoreCol.GetSlotNames(ref slotNames);
    var labels = slotNames.DenseValues().Select(v => v.ToString()).ToArray();

    _logger.LogInformation("Label order: {Labels}", string.Join(", ", labels));

    // Evaluate
    var predictions = model.Transform(split.TestSet);
    var metrics = mlContext.MulticlassClassification.Evaluate(
        predictions, labelColumnName: "Label");

    _logger.LogInformation("========== Model Evaluation ==========");
    _logger.LogInformation("MacroAccuracy:    {MacroAccuracy:F4}", metrics.MacroAccuracy);
    _logger.LogInformation("MicroAccuracy:    {MicroAccuracy:F4}", metrics.MicroAccuracy);
    _logger.LogInformation("LogLoss:          {LogLoss:F4}", metrics.LogLoss);
    _logger.LogInformation("LogLossReduction: {LogLossReduction:F4}", metrics.LogLossReduction);

    for (var i = 0; i < labels.Length; i++)
    {
        _logger.LogInformation("  {Label} LogLoss: {LogLoss:F4}",
            labels[i], metrics.PerClassLogLoss[i]);
    }
    _logger.LogInformation("=======================================");

    // Cross-validation for more reliable metrics on small datasets
    _logger.LogInformation("Running 5-fold cross-validation...");
    var cvResults = mlContext.MulticlassClassification.CrossValidate(
        data, pipeline, numberOfFolds: 5, labelColumnName: "Label");

    var avgMacro = cvResults.Average(r => r.Metrics.MacroAccuracy);
    var avgMicro = cvResults.Average(r => r.Metrics.MicroAccuracy);
    _logger.LogInformation("Cross-Validation Avg MacroAccuracy: {Avg:F4}", avgMacro);
    _logger.LogInformation("Cross-Validation Avg MicroAccuracy: {Avg:F4}", avgMicro);

    // Save model
    mlContext.Model.Save(model, split.TrainSet.Schema, _modelPath);
    _logger.LogInformation("Model saved to {Path}", _modelPath);

    return new TicketModelMetadata { Labels = labels };
}

